compliant:
// Use modern, safe alternatives
#include <memory>
#include <string>
#include <cstring>

class ModernSmartPtr {
    std::unique_ptr<int> data;
};

char* secure_strcpy(char* dest, const char* src, size_t dest_size) {
    return strncpy(dest, src, dest_size - 1);
}

DWORD GetTickCount64() {
    // 64-bit safe implementation
    return 0;
}

void goodExample() {
    ModernSmartPtr ptr;        // Compliant - using modern class
    char buffer[100];
    secure_strcpy(buffer, "test", sizeof(buffer)); // Compliant - using secure function
    DWORD ticks = GetTickCount64(); // Compliant - using 64-bit safe API
}

// Safe string handling practices
#include <string>
#include <iostream>
void safeCode() {
    std::string dest;
    std::string src = "Hello World";
    dest = src;                    // Compliant - safe string assignment
    std::getline(std::cin, dest); // Compliant - safe input method

    // If you must use C-style strings, use safe functions
    char buffer[100];
    strncpy(buffer, src.c_str(), sizeof(buffer) - 1); // Compliant - bounded copy
    buffer[sizeof(buffer) - 1] = '\0'; // Ensure null termination
}
